```PREFIX yago: <http://dbpedia.org/class/yago/>
PREFIX res: <http://dbpedia.org/resource/>
PREFIX dbp: <http://dbpedia.org/property/>
PREFIX dbo: <http://dbpedia.org/ontology/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?state WHERE {
  {
    res:Utah dbp:timezone ?tz .
    ?state rdf:type yago:WikicatStatesOfTheUnitedStates ;
           dbp:timezone ?tz .
    FILTER (?state != res:Utah)
  }
  UNION
  {
    res:San_Pedro_de_Atacama dbo:timeZone ?tzName .
    BIND(?tzName AS ?state)
  }
}
```

```PREFIX dbo: <http://dbpedia.org/ontology/>
PREFIX dbr: <http://dbpedia.org/resource/>

SELECT DISTINCT ?mountain WHERE {
  ?mountain a dbo:Mountain ;
            dbo:elevation ?elevation .
  {
    # For highest mountain in Saxony, Germany: restrict to mountains within Saxony region or Ore Mountains in Saxony
    ?mountain dbo:location ?location .
    ?location (dbo:isPartOf)* dbr:Saxony .
  }
}
ORDER BY DESC(?elevation)
LIMIT 1
```

