         dbo:highlights ?h .
    FILTER regex(str(?h), "MVP", "i")
  }
  UNION
  {
    ?uri rdf:type dbo:SoccerClub ;
         dbo:league <http://dbpedia.org/resource/Premier_League>
  }
}
ORDER BY DESC(?date)
LIMIT 4
```

