          dbo:country res:Spain ;
          dbo:producer res:Benicio_del_Toro ;
          dbo:starring ?star .
    ?star rdf:type dbo:Person .
    BIND(?star AS ?starInSpanishMovies)
  }
  UNION
  {
    res:Arnold_Schwarzenegger dbo:almaMater ?uni .
    ?uni rdf:type dbo:University .
    BIND(true AS ?arnoldAttendedUniversity)
  }
}
LIMIT 10
